11	 * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * * */
12	
13	#include "H5IMprivate.h"
14	#include "H5LTprivate.h"
15	
16	/*-------------------------------------------------------------------------
17	 * Function: H5IMmake_image_8bit
18	 *
19	 * Purpose: Creates and writes an image an 8 bit image
20	 *
21	 * Return: Success: 0, Failure: -1
22	 *
23	 * Comments:
24	 *  based on HDF5 Image and Palette Specification
25	 *
26	 *-------------------------------------------------------------------------
27	 */
28	
29	herr_t
30	H5IMmake_image_8bit(hid_t loc_id, const char *dset_name, hsize_t width, hsize_t height,
31	                    const unsigned char *buf)
32	{
33	    hsize_t dims[IMAGE8_RANK];
34	
35	    /* check the arguments */
36	    if (dset_name == NULL)
37	        return -1;
38	
39	    /* Initialize the image dimensions */
40	    dims[0] = height;
41	    dims[1] = width;
42	
43	    /* Make the dataset */
44	    if (H5LTmake_dataset(loc_id, dset_name, IMAGE8_RANK, dims, H5T_NATIVE_UCHAR, buf) < 0)
45	        return -1;
46	
47	    /* Attach the CLASS attribute */
48	    if (H5LTset_attribute_string(loc_id, dset_name, "CLASS", IMAGE_CLASS) < 0)
49	        return -1;
50	
51	    /* Attach the VERSION attribute */
52	    if (H5LTset_attribute_string(loc_id, dset_name, "IMAGE_VERSION", IMAGE_VERSION) < 0)
53	        return -1;
54	
55	    /* Attach the IMAGE_SUBCLASS attribute */
56	    if (H5LTset_attribute_string(loc_id, dset_name, "IMAGE_SUBCLASS", "IMAGE_INDEXED") < 0)
57	        return -1;
58	
59	    return 0;
60	}
61	
62	/*-------------------------------------------------------------------------
63	 * Function: H5IMmake_image_24bit
64	 *
65	 * Purpose:
66	 *
67	 * Return: Success: 0, Failure: -1
68	 *
69	 * Comments:
70	 *  based on HDF5 Image and Palette Specification
71	 *
72	 * Interlace Mode Dimensions in the Dataspace
73	 * INTERLACE_PIXEL [height][width][pixel components]
74	 * INTERLACE_PLANE [pixel components][height][width]
75	 *
76	 *-------------------------------------------------------------------------
77	 */
78	
79	herr_t
80	H5IMmake_image_24bit(hid_t loc_id, const char *dset_name, hsize_t width, hsize_t height,
81	                     const char *interlace, const unsigned char *buf)
82	{
83	    hsize_t dims[IMAGE24_RANK];
84	
85	    /* check the arguments */
86	    if (interlace == NULL)
87	        return -1;
88	    if (dset_name == NULL)
89	        return -1;
90	
91	    /* Initialize the image dimensions */
92	
93	    if (strncmp(interlace, "INTERLACE_PIXEL", 15) == 0) {
94	        /* Number of color planes is defined as the third dimension */
95	        dims[0] = height;
96	        dims[1] = width;
97	        dims[2] = IMAGE24_RANK;
98	    }
99	    else if (strncmp(interlace, "INTERLACE_PLANE", 15) == 0) {
100	        /* Number of color planes is defined as the first dimension */
101	        dims[0] = IMAGE24_RANK;
102	        dims[1] = height;
103	        dims[2] = width;
104	    }
105	    else
106	        return -1;
107	
108	    /* Make the dataset */
109	    if (H5LTmake_dataset(loc_id, dset_name, IMAGE24_RANK, dims, H5T_NATIVE_UCHAR, buf) < 0)
110	        return -1;
111	
112	    /* Attach the CLASS attribute */
113	    if (H5LTset_attribute_string(loc_id, dset_name, "CLASS", IMAGE_CLASS) < 0)
114	        return -1;
115	
116	    /* Attach the VERSION attribute */
117	    if (H5LTset_attribute_string(loc_id, dset_name, "IMAGE_VERSION", IMAGE_VERSION) < 0)
118	        return -1;
119	
120	    /* Attach the IMAGE_SUBCLASS attribute */
121	    if (H5LTset_attribute_string(loc_id, dset_name, "IMAGE_SUBCLASS", "IMAGE_TRUECOLOR") < 0)
122	        return -1;
123	
124	    /* Attach the INTERLACE_MODE attribute. This attributes is only for true color images */
125	    if (H5LTset_attribute_string(loc_id, dset_name, "INTERLACE_MODE", interlace) < 0)
126	        return -1;
127	
128	    return 0;
129	}
130	
131	/*-------------------------------------------------------------------------
132	 * Function: find_palette
133	 *
134	 * Purpose: operator function used by H5LT_find_palette
135	 *
136	 * Return:
137	 *
138	 * Comments:
139	 *
140	 *-------------------------------------------------------------------------
141	 */
142	static herr_t
143	find_palette(H5_ATTR_UNUSED hid_t loc_id, const char *name, H5_ATTR_UNUSED const H5A_info_t *ainfo,
144	             H5_ATTR_UNUSED void *op_data)
145	{
146	    int ret = H5_ITER_CONT;
147	
148	    /* check the arguments */
149	    if (name == NULL)
150	        return -1;
151	
152	    /* Shut compiler up */
153	    (void)loc_id;
154	    (void)ainfo;
155	    (void)op_data;
156	
157	    /* Define a positive value for return value if the attribute was found. This will
158	     * cause the iterator to immediately return that positive value,
159	     * indicating short-circuit success
160	     */
161	    if (strncmp(name, "PALETTE", 7) == 0)
162	        ret = H5_ITER_STOP;
163	
164	    return ret;
165	}
166	
167	/*-------------------------------------------------------------------------
168	 * Function: H5IM_find_palette
169	 *
170	 * Purpose: Private function. Find the attribute "PALETTE" in the image dataset
171	 *
172	 * Return: Success: 1, Failure: 0
173	 *
174	 * Comments:
175	 *  The function uses H5Aiterate2 with the operator function find_palette
176	 *
177	 *-------------------------------------------------------------------------
178	 */
179	
180	herr_t
181	H5IM_find_palette(hid_t loc_id)
182	{
183	    return H5Aiterate2(loc_id, H5_INDEX_NAME, H5_ITER_INC, NULL, find_palette, NULL);
184	}
185	
186	/*-------------------------------------------------------------------------
187	 * Function: H5IMget_image_info
188	 *
189	 * Purpose: Gets information about an image dataset (dimensions, interlace mode
190	 *          and number of associated palettes).
191	 *
192	 * Return: Success: 0, Failure: -1
193	 *
194	 * Comments:
195	 *  based on HDF5 Image and Palette Specification
196	 *
197	 *-------------------------------------------------------------------------
198	 */
199	herr_t
200	H5IMget_image_info(hid_t loc_id, const char *dset_name, hsize_t *width, hsize_t *height, hsize_t *planes,
201	                   char *interlace, hssize_t *npals)
202	{
203	    hid_t       did = -1;
204	    hid_t       sid = -1;
205	    hsize_t     dims[IMAGE24_RANK];
206	    hid_t       aid  = -1;
207	    hid_t       asid = -1;
208	    hid_t       atid = -1;
209	    H5T_class_t aclass;
210	    int         has_pal;
211	    hid_t       has_attr;
212	
213	    /* check the arguments */
214	    if (dset_name == NULL)
215	        return -1;
216	    if (interlace == NULL)
217	        return -1;
218	
219	    /*assume initially we have no palettes attached*/
220	    *npals = 0;
221	
222	    /* Open the dataset. */
223	    if ((did = H5Dopen2(loc_id, dset_name, H5P_DEFAULT)) < 0)
224	        return -1;
225	
226	    /* Try to find the attribute "INTERLACE_MODE" on the >>image<< dataset */
227	    if ((has_attr = H5Aexists(did, "INTERLACE_MODE")) < 0)
228	        goto out;
229	
230	    /* It exists, get it */
231	    if (has_attr > 0) {
232	
233	        if ((aid = H5Aopen(did, "INTERLACE_MODE", H5P_DEFAULT)) < 0)
234	            goto out;
235	
236	        if ((atid = H5Aget_type(aid)) < 0)
237	            goto out;
238	
239	        if (H5Aread(aid, atid, interlace) < 0)
240	            goto out;
241	
242	        if (H5Tclose(atid) < 0)
243	            goto out;
244	
245	        if (H5Aclose(aid) < 0)
246	            goto out;
247	    }
248	
249	    /* Get the dataspace handle */
250	    if ((sid = H5Dget_space(did)) < 0)
251	        goto out;
252	
253	    if (H5Sget_simple_extent_dims(sid, NULL, NULL) > IMAGE24_RANK)
254	        goto out;
255	    /* Get dimensions */
256	    if (H5Sget_simple_extent_dims(sid, dims, NULL) < 0)
257	        goto out;
258	
259	    /* Initialize the image dimensions */
260	
261	    if (has_attr > 0) {
262	        /* This is a 24 bit image */
263	
264	        if (strncmp(interlace, "INTERLACE_PIXEL", 15) == 0) {
265	            /* Number of color planes is defined as the third dimension */
266	            *height = dims[0];
267	            *width  = dims[1];
268	            *planes = dims[2];
269	        }
270	        else if (strncmp(interlace, "INTERLACE_PLANE", 15) == 0) {
271	            /* Number of color planes is defined as the first dimension */
272	            *planes = dims[0];
273	            *height = dims[1];
274	            *width  = dims[2];
275	        }
276	        else
277	            return -1;
278	    }
279	    else {
280	        /* This is a 8 bit image */
281	        *height = dims[0];
282	        *width  = dims[1];
283	        *planes = 1;
284	    }
285	
286	    /* Close */
287	    if (H5Sclose(sid) < 0)
288	        goto out;
289	
290	    /* Get number of palettes */
291	
292	    /* Try to find the attribute "PALETTE" on the >>image<< dataset */
293	    has_pal = H5IM_find_palette(did);
294	
295	    if (has_pal == 1) {
296	
297	        if ((aid = H5Aopen(did, "PALETTE", H5P_DEFAULT)) < 0)
298	            goto out;
299	
300	        if ((atid = H5Aget_type(aid)) < 0)
301	            goto out;
302	
303	        if ((aclass = H5Tget_class(atid)) < 0)
304	            goto out;
305	
306	        /* Check if it is really a reference */
307	
308	        if (aclass == H5T_REFERENCE) {
309	
310	            /* Get the reference(s) */
311	
312	            if ((asid = H5Aget_space(aid)) < 0)
313	                goto out;
314	
315	            *npals = H5Sget_simple_extent_npoints(asid);
316	
317	            if (H5Sclose(asid) < 0)
318	                goto out;
319	
320	        } /* H5T_REFERENCE */
321	
322	        if (H5Tclose(atid) < 0)
323	            goto out;
324	
325	        /* Close the attribute. */
326	        if (H5Aclose(aid) < 0)
327	            goto out;
328	    }
329	
330	    /* End access to the dataset and release resources used by it. */
331	    if (H5Dclose(did) < 0)
332	        goto out;
333	
334	    return 0;
335	
336	out:
337	    if (did > 0)
338	        H5Dclose(did);
339	    if (aid > 0)
340	        H5Aclose(aid);
341	    if (asid > 0)
342	        H5Sclose(asid);
343	    if (atid > 0)
344	        H5Tclose(atid);
345	    return -1;
346	}
347	
348	/*-------------------------------------------------------------------------
349	 * Function: H5IMread_image
350	 *
351	 * Purpose: Reads image data from disk.
352	 *
353	 * Return: Success: 0, Failure: -1
354	 *
355	 * Comments:
356	 *  based on HDF5 Image and Palette Specification
357	 *
358	 *-------------------------------------------------------------------------
359	 */
360	
361	herr_t
362	H5IMread_image(hid_t loc_id, const char *dset_name, unsigned char *buf)
363	{
364	    hid_t did;
365	
366	    /* check the arguments */
367	    if (dset_name == NULL)
368	        return -1;
369	
370	    /* Open the dataset. */
371	    if ((did = H5Dopen2(loc_id, dset_name, H5P_DEFAULT)) < 0)
372	        return -1;
373	
374	    /* Read */
375	    if (H5Dread(did, H5T_NATIVE_UCHAR, H5S_ALL, H5S_ALL, H5P_DEFAULT, buf) < 0)
376	        goto out;
377	
378	    /* End access to the dataset and release resources used by it. */
379	    if (H5Dclose(did))
380	        return -1;
381	
382	    return 0;
383	
384	out:
385	    H5Dclose(did);
386	    return -1;
387	}
388	
389	/*-------------------------------------------------------------------------
390	 * Function: H5IMmake_palette
391	 *
392	 * Purpose: Creates and writes a palette.
393	 *
394	 * Return: Success: 0, Failure: -1
395	 *
396	 * Comments:
397	 *  based on HDF5 Image and Palette Specification
398	 *
399	 *-------------------------------------------------------------------------
400	 */
401	
402	herr_t
403	H5IMmake_palette(hid_t loc_id, const char *pal_name, const hsize_t *pal_dims, const unsigned char *pal_data)
404	
405	{
406	
407	    int has_pal;
408	
409	    /* check the arguments */
410	    if (pal_name == NULL)
411	        return -1;
412	
413	    /* Check if the dataset already exists */
414	    has_pal = H5LTfind_dataset(loc_id, pal_name);
415	
416	    /* It exists. Return */
417	    if (has_pal == 1)
418	        return 0;
419	
420	    /* Make the palette dataset. */
421	    if (H5LTmake_dataset(loc_id, pal_name, 2, pal_dims, H5T_NATIVE_UCHAR, pal_data) < 0)
422	        return -1;
423	
424	    /* Attach the attribute "CLASS" to the >>palette<< dataset*/
425	    if (H5LTset_attribute_string(loc_id, pal_name, "CLASS", PALETTE_CLASS) < 0)
426	        return -1;
427	
428	    /* Attach the attribute "PAL_VERSION" to the >>palette<< dataset*/
429	    if (H5LTset_attribute_string(loc_id, pal_name, "PAL_VERSION", "1.2") < 0)
430	        return -1;
431	
432	    return 0;
433	}
434	
435	/*-------------------------------------------------------------------------
436	 * Function: H5IMlink_palette
437	 *
438	 * Purpose: This function attaches a palette to an existing image dataset
439	 *
440	 * Return: Success: 0, Failure: -1
441	 *
442	 * Comments:
443	 *  based on HDF5 Image and Palette Specification
444	 *
445	 *  An image (dataset) within an HDF5 file may optionally specify an array of
446	 *  palettes to be viewed with. The dataset will have an attribute
447	 *  which contains an array of object reference pointers which refer to palettes in the file.
448	 *
449	 *-------------------------------------------------------------------------
450	 */
451	
452	herr_t
453	H5IMlink_palette(hid_t loc_id, const char *image_name, const char *pal_name)
454	
455	{
456	    hid_t       did;
457	    hid_t       atid = -1;
458	    hid_t       aid  = -1;
459	    hid_t       asid = -1;
460	    hobj_ref_t  ref;    /* write a new reference */
461	    hobj_ref_t *refbuf; /* buffer to read references */
462	    hssize_t    n_refs;
463	    hsize_t     dim_ref;
464	    htri_t      ok_pal;
465	
466	    /* check the arguments */
467	    if (image_name == NULL)
468	        return -1;
469	    if (pal_name == NULL)
470	        return -1;
471	
472	    /* The image dataset may or may not have the attribute "PALETTE"
473	     * First we try to open to see if it is already there; if not, it is created.
474	     * If it exists, the array of references is extended to hold the reference
475	     * to the new palette
476	     */
477	
478	    /* First we get the image id */
479	    if ((did = H5Dopen2(loc_id, image_name, H5P_DEFAULT)) < 0)
480	        return -1;
481	
482	    /* Try to find the attribute "PALETTE" on the >>image<< dataset */
483	    if ((ok_pal = H5Aexists(did, "PALETTE")) < 0)
484	        goto out;
485	
486	    /*-------------------------------------------------------------------------
487	     * It does not exist. We create the attribute and one reference
488	     *-------------------------------------------------------------------------
489	     */
490	    if (ok_pal == 0) {
491	        if ((asid = H5Screate(H5S_SCALAR)) < 0)
492	            goto out;
493	
494	        /* Create the attribute type for the reference */
495	        if ((atid = H5Tcopy(H5T_STD_REF_OBJ)) < 0)
496	            goto out;
497	
498	        /* Create the attribute "PALETTE" to be attached to the image*/
499	        if ((aid = H5Acreate2(did, "PALETTE", atid, asid, H5P_DEFAULT, H5P_DEFAULT)) < 0)
500	            goto out;
501	
502	        /* Create a reference. The reference is created on the local id.  */
503	        if (H5Rcreate(&ref, loc_id, pal_name, H5R_OBJECT, (hid_t)-1) < 0)
504	            goto out;
505	
506	        /* Write the attribute with the reference */
507	        if (H5Awrite(aid, atid, &ref) < 0)
508	            goto out;
509	
510	        /* close */
511	        if (H5Sclose(asid) < 0)
512	            goto out;
513	        if (H5Tclose(atid) < 0)
514	            goto out;
515	        if (H5Aclose(aid) < 0)
516	            goto out;
517	    }
518	
519	    /*-------------------------------------------------------------------------
520	     * The attribute already exists, open it
521	     *-------------------------------------------------------------------------
522	     */
523	    else if (ok_pal > 0) {
524	        if ((aid = H5Aopen(did, "PALETTE", H5P_DEFAULT)) < 0)
525	            goto out;
526	
527	        if ((atid = H5Aget_type(aid)) < 0)
528	            goto out;
529	
530	        if (H5Tget_class(atid) < 0)
531	            goto out;
532	
533	        /* Get and save the old reference(s) */
534	        if ((asid = H5Aget_space(aid)) < 0)
535	            goto out;
536	
537	        n_refs = H5Sget_simple_extent_npoints(asid);
538	
539	        dim_ref = (hsize_t)n_refs + 1;
540	
541	        refbuf = (hobj_ref_t *)malloc(sizeof(hobj_ref_t) * (size_t)dim_ref);
542	
543	        if (H5Aread(aid, atid, refbuf) < 0)
544	            goto out;
545	
546	        /* The attribute must be deleted, in order to the new one can reflect the changes*/
547	        if (H5Adelete(did, "PALETTE") < 0)
548	            goto out;
549	
550	        /* Create a new reference for this palette. */
551	        if (H5Rcreate(&ref, loc_id, pal_name, H5R_OBJECT, (hid_t)-1) < 0)
552	            goto out;
553	
554	        refbuf[n_refs] = ref;
555	
556	        /* Create the data space for the new references */
557	        if (H5Sclose(asid) < 0)
558	            goto out;
559	
560	        if ((asid = H5Screate_simple(1, &dim_ref, NULL)) < 0)
561	            goto out;
562	
563	        /* Create the attribute again with the changes of space */
564	        if (H5Aclose(aid) < 0)
565	            goto out;
566	
567	        if ((aid = H5Acreate2(did, "PALETTE", atid, asid, H5P_DEFAULT, H5P_DEFAULT)) < 0)
568	            goto out;
569	
570	        /* Write the attribute with the new references */
571	        if (H5Awrite(aid, atid, refbuf) < 0)
572	            goto out;
573	
574	        /* close */
575	        if (H5Sclose(asid) < 0)
576	            goto out;
577	        if (H5Tclose(atid) < 0)
578	            goto out;
579	        if (H5Aclose(aid) < 0)
580	            goto out;
581	
582	        free(refbuf);
583	
584	    } /* ok_pal > 0 */
585	
586	    /* Close the image dataset. */
587	    if (H5Dclose(did) < 0)
588	        return -1;
589	
590	    return 0;
591	
592	out:
593	    H5Dclose(did);
594	    H5Sclose(asid);
595	    H5Tclose(atid);
596	    H5Aclose(aid);
597	    return -1;
598	}
