613	herr_t
614	H5IMunlink_palette(hid_t loc_id, const char *image_name, const char *pal_name)
615	{
616	    hid_t       did;
617	    hid_t       atid;
618	    hid_t       aid;
619	    H5T_class_t aclass;
620	    htri_t      ok_pal;
621	    int         has_pal;
622	
623	    /* check the arguments */
624	    if (image_name == NULL)
625	        return -1;
626	    if (pal_name == NULL)
627	        return -1;
628	
629	    /* Try to find the palette dataset */
630	    has_pal = H5LTfind_dataset(loc_id, pal_name);
631	
632	    /* It does not exist. Return */
633	    if (has_pal == 0)
634	        return -1;
635	
636	    /* The image dataset may or not have the attribute "PALETTE"
637	     * First we try to open to see if it is already there; if not, it is created.
638	     * If it exists, the array of references is extended to hold the reference
639	     * to the new palette
640	     */
641	
642	    /* First we get the image id */
643	    if ((did = H5Dopen2(loc_id, image_name, H5P_DEFAULT)) < 0)
644	        return -1;
645	
646	    /* Try to find the attribute "PALETTE" on the >>image<< dataset */
647	    if ((ok_pal = H5Aexists(did, "PALETTE")) < 0)
648	        goto out;
649	
650	    /* It does not exist. Nothing to do */
651	    if (ok_pal == 0)
652	        goto out;
653	    else if (ok_pal > 0) {
654	        /* The attribute exists, open it */
655	        if ((aid = H5Aopen(did, "PALETTE", H5P_DEFAULT)) < 0)
656	            goto out;
657	
658	        if ((atid = H5Aget_type(aid)) < 0)
659	            goto out;
660	
661	        if ((aclass = H5Tget_class(atid)) < 0)
662	            goto out;
663	
664	        /* Check if it is really a reference */
665	        if (aclass == H5T_REFERENCE) {
666	            /* Delete the attribute */
667	            if (H5Adelete(did, "PALETTE") < 0)
668	                goto out;
669	
670	        } /* H5T_REFERENCE */
671	
672	        if (H5Tclose(atid) < 0)
673	            goto out;
674	
675	        /* Close the attribute. */
676	        if (H5Aclose(aid) < 0)
677	            goto out;
678	    }
679	
680	    /* Close the image dataset. */
681	    if (H5Dclose(did) < 0)
682	        return -1;
683	
684	    return 0;
685	
686	out:
687	    H5Dclose(did);
688	    return -1;
689	}
