969	/*-------------------------------------------------------------------------
970	 * Function: H5IM__class_attr_equals
971	 *
972	 * Purpose: Opens dset_name under loc_id, reads its "CLASS" attribute
973	 *          (fixed-length or variable-length string), and returns 1 if the
974	 *          value equals expected, 0 if it does not, or -1 on error.
975	 *
976	 *-------------------------------------------------------------------------
977	 */
978	static htri_t
979	H5IM__class_attr_equals(hid_t loc_id, const char *dset_name, const char *expected)
980	{
981	    hid_t   did       = H5I_INVALID_HID;
982	    hid_t   atid      = H5I_INVALID_HID;
983	    hid_t   aid       = H5I_INVALID_HID;
984	    char   *attr_data = NULL;
985	    htri_t  has_class;
986	    htri_t  isvl;
987	    hsize_t storage_size;
988	    htri_t  ret = -1;
989	
990	    if (dset_name == NULL)
991	        return -1;
992	
993	    if ((did = H5Dopen2(loc_id, dset_name, H5P_DEFAULT)) < 0)
994	        goto out;
995	
996	    if ((has_class = H5Aexists(did, "CLASS")) < 0)
997	        goto out;
998	
999	    if (has_class == 0) {
1000	        ret = 0;
1001	        goto out;
1002	    }
1003	
1004	    if ((aid = H5Aopen(did, "CLASS", H5P_DEFAULT)) < 0)
1005	        goto out;
1006	
1007	    if ((atid = H5Aget_type(aid)) < 0)
1008	        goto out;
1009	
1010	    if (H5T_STRING != H5Tget_class(atid))
1011	        goto out;
1012	
1013	    if ((isvl = H5Tis_variable_str(atid)) < 0)
1014	        goto out;
1015	
1016	    if (isvl > 0) {
1017	        /* Variable-length string: H5Aread allocates the string and writes
1018	         * its address into the buffer; use H5Treclaim to free it after use. */
1019	        char *vl_str = NULL;
1020	        hid_t sid    = H5I_INVALID_HID;
1021	
1022	        if ((sid = H5Aget_space(aid)) < 0)
1023	            goto out;
1024	        if (H5Aread(aid, atid, &vl_str) < 0) {
1025	            H5Sclose(sid);
1026	            goto out;
1027	        }
1028	        ret = (vl_str && strcmp(vl_str, expected) == 0) ? 1 : 0;
1029	        H5Treclaim(atid, sid, H5P_DEFAULT, &vl_str);
1030	        H5Sclose(sid);
1031	    }
1032	    else {
1033	        if (H5T_STR_NULLTERM != H5Tget_strpad(atid))
1034	            goto out;
1035	
1036	        if ((storage_size = H5Aget_storage_size(aid)) == 0)
1037	            goto out;
1038	
1039	        /* Allocate one extra byte; force null termination in case the attribute
1040	         * was written without honoring H5T_STR_NULLTERM. */
1041	        attr_data = (char *)malloc((size_t)storage_size * sizeof(char) + 1);
1042	        if (attr_data == NULL)
1043	            goto out;
1044	
1045	        if (H5Aread(aid, atid, attr_data) < 0)
1046	            goto out;
1047	        attr_data[storage_size] = '\0';
1048	
1049	        ret = (strcmp(attr_data, expected) == 0) ? 1 : 0;
1050	    }
1051	
1052	out:
1053	    free(attr_data);
1054	    H5E_BEGIN_TRY
1055	    {
1056	        H5Tclose(atid);
1057	        H5Aclose(aid);
1058	        H5Dclose(did);
1059	    }
1060	    H5E_END_TRY
1061	    return ret;
1062	}
1063	
1064	/*-------------------------------------------------------------------------
1065	 * Function: H5IMis_image
1066	 *
1067	 * Purpose:
1068	 *
1069	 * Return: true, false, fail
1070	 *
1071	 * Comments:
1072	 *  based on HDF5 Image and Palette Specification
1073	 *
1074	 *-------------------------------------------------------------------------
1075	 */
1076	
1077	herr_t
1078	H5IMis_image(hid_t loc_id, const char *dset_name)
1079	{
1080	    return H5IM__class_attr_equals(loc_id, dset_name, IMAGE_CLASS);
1081	}
1082	
1083	/*-------------------------------------------------------------------------
1084	 * Function: H5IMis_palette
1085	 *
1086	 * Purpose:
1087	 *
1088	 * Return: true, false, fail
1089	 *
1090	 * Comments:
1091	 *  based on HDF5 Image and Palette Specification
1092	 *
1093	 *-------------------------------------------------------------------------
1094	 */
1095	
1096	herr_t
1097	H5IMis_palette(hid_t loc_id, const char *dset_name)
1098	{
1099	    return H5IM__class_attr_equals(loc_id, dset_name, PALETTE_CLASS);
1100	}
